     2→ * CONVERGIO EDUCATION - FSRS (Free Spaced Repetition Scheduler)
     3→ *
     4→ * TypeScript implementation of the FSRS algorithm (2024 version) for optimal
     5→ * spaced repetition scheduling based on Duolingo's research.
     6→ *
     7→ * Algorithm: Stability = S * (11^D - 1) * e^(k*(1-R)) * e^(0.2*t) * e^(-0.1*lapse)
     8→ *
     9→ * Phase: FASE 11 - Learning Science
    10→ *
    11→ * Copyright (c) 2025 Convergio.io
    12→ * Licensed under MIT License
    13→ */
    14→
    15→// ============================================================================
    16→// CONSTANTS
    17→// ============================================================================
    18→
    19→const FSRS_INITIAL_STABILITY = 1.0;
    20→const FSRS_INITIAL_DIFFICULTY = 0.3;
    21→const FSRS_DESIRED_RETENTION = 0.9;
    22→const FSRS_K_FACTOR = 19.0; // Controls stability growth rate
    23→const FSRS_DECAY_SHARPNESS = 0.95; // Power law decay parameter
    24→
    25→// Quality bounds
    26→const MIN_STABILITY_DAYS = 0.04; // 1 hour minimum
    27→const MAX_STABILITY_DAYS = 1095; // 3 years maximum
    28→const MAX_INTERVAL_HOURS = 365 * 24; // 1 year maximum
    29→
    30→// ============================================================================
    31→// TYPES
    32→// ============================================================================
    33→
    34→/**
    35→ * Quality rating for a review session
    36→ * 1 = Again (forgot) - card will be shown again soon
    37→ * 2 = Hard - remembered with difficulty
    38→ * 3 = Good - remembered correctly
    39→ * 4 = Easy - remembered very easily
    40→ */
    41→export type Quality = 1 | 2 | 3 | 4;
    42→
    43→/**
    44→ * FSRS flashcard state
    45→ */
    46→export interface FSRSCard {
    47→  /** Stability: days until 90% forgetting probability */
    48→  stability: number;
    49→
    50→  /** Difficulty: 0 (easy) to 1 (hard) */
    51→  difficulty: number;
    52→
    53→  /** Last review timestamp */
    54→  lastReview: Date;
    55→
    56→  /** Next scheduled review timestamp */
    57→  nextReview: Date;
    58→
    59→  /** Number of times the card was forgotten */
    60→  lapses: number;
    61→
    62→  /** Total number of reviews */
    63→  reps: number;
    64→}
    65→
    66→/**
    67→ * Statistics for FSRS performance tracking
    68→ */
    69→export interface FSRSStats {
    70→  totalCards: number;
    71→  cardsDue: number;
    72→  cardsMastered: number; // stability > 30 days
    73→  avgStability: number;
    74→  avgDifficulty: number;
    75→  predictedRetention: number;
    76→}
    77→
    78→// ============================================================================
    79→// CORE FSRS ALGORITHM
    80→// ============================================================================
    81→
    82→/**
    83→ * Calculate retrievability (probability of recall) based on elapsed time
    84→ *
    85→ * Formula: R(t) = (1 + t/(9*S))^(-1/w)
    86→ * where:
    87→ *   - t = days elapsed since last review
    88→ *   - S = stability (days until 90% forgetting)
    89→ *   - w = decay sharpness parameter (0.95)
    90→ *
    91→ * @param card - The flashcard to calculate retrievability for
    92→ * @returns Probability of recall (0.0 to 1.0)
    93→ */
    94→export function calculateRetrievability(card: FSRSCard): number {
    95→  const now = new Date();
    96→  const daysElapsed = (now.getTime() - card.lastReview.getTime()) / (1000 * 60 * 60 * 24);
    97→
    98→  if (card.stability <= 0 || daysElapsed < 0) {
    99→    return 1.0;
   100→  }
   101→
   102→  // Power law decay with stability as the time constant
   103→  const r = Math.pow(1.0 + daysElapsed / (9.0 * card.stability), -1.0 / FSRS_DECAY_SHARPNESS);
   104→
   105→  // Clamp to [0, 1]
   106→  return Math.max(0.0, Math.min(1.0, r));
   107→}
   108→
   109→/**
   110→ * Calculate new stability based on review quality
   111→ *
   112→ * Uses FSRS-5 algorithm with quality-based modifiers:
   113→ * - Again (1): Stability reduced to 30% with difficulty penalty
   114→ * - Hard (2): 60% of calculated stability
   115→ * - Good (3): 85% of calculated stability
   116→ * - Easy (4): 130% of calculated stability
   117→ *
   118→ * @param S - Current stability
   119→ * @param D - Current difficulty
   120→ * @param R - Current retrievability
   121→ * @param quality - Quality rating (1-4)
   122→ * @param lapses - Number of times forgotten
   123→ * @returns New stability value
   124→ */
   125→function calculateNewStability(
   126→  S: number,
   127→  D: number,
   128→  R: number,
   129→  quality: Quality,
   130→  lapses: number
   131→): number {
   132→  // Quality 1 (Again/Forgot) - significantly reduce stability
   133→  if (quality === 1) {
   134→    const newS = S * 0.3 * Math.pow(11.0, D - 1.0);
   135→    return Math.max(MIN_STABILITY_DAYS, Math.min(MAX_STABILITY_DAYS, newS));
   136→  }
   137→
   138→  // FSRS formula for successful recall
   139→  const k = FSRS_K_FACTOR;
   140→  const base = 11.0;
   141→
   142→  let stability = S * (Math.pow(base, D) - 1.0) *
   143→                  Math.exp(k * (1.0 - R)) *
   144→                  Math.exp(0.2 * S) *
   145→                  Math.exp(-0.1 * lapses);
   146→
   147→  // Apply quality modifiers
   148→  switch (quality) {
   149→    case 2: // Hard
   150→      stability *= 0.6;
   151→      break;
   152→    case 3: // Good
   153→      stability *= 0.85;
   154→      break;
   155→    case 4: // Easy
   156→      stability *= 1.3;
   157→      break;
   158→  }
   159→
   160→  // Clamp to reasonable bounds (1 hour to 3 years)
   161→  return Math.max(MIN_STABILITY_DAYS, Math.min(MAX_STABILITY_DAYS, stability));
   162→}
   163→
   164→/**
   165→ * Calculate new difficulty based on review quality
   166→ *
   167→ * Difficulty adjusts based on performance:
   168→ * - Again (1): +0.1 (harder)
   169→ * - Hard (2): +0.05
   170→ * - Good (3): -0.03
   171→ * - Easy (4): -0.07 (easier)
   172→ *
   173→ * Includes mean reversion toward 0.3
   174→ *
   175→ * @param D - Current difficulty
   176→ * @param quality - Quality rating (1-4)
   177→ * @returns New difficulty value (0.0 to 1.0)
   178→ */
   179→function calculateNewDifficulty(D: number, quality: Quality): number {
   180→  let delta = 0.0;
   181→
   182→  switch (quality) {
   183→    case 1: // Again
   184→      delta = 0.1;
   185→      break;
   186→    case 2: // Hard
   187→      delta = 0.05;
   188→      break;
   189→    case 3: // Good
   190→      delta = -0.03;
   191→      break;
   192→    case 4: // Easy
   193→      delta = -0.07;
   194→      break;
   195→  }
   196→
   197→  // Mean reversion toward 0.3
   198→  const newD = D + delta + 0.05 * (0.3 - D);
   199→
   200→  // Clamp to [0, 1]
   201→  return Math.max(0.0, Math.min(1.0, newD));
   202→}
   203→
   204→/**
   205→ * Calculate optimal interval until next review
   206→ *
   207→ * Solves R(t) = desired_retention for t:
   208→ * t = S * ((1/R)^w - 1) * 9
   209→ *
   210→ * @param stability - Current stability in days
   211→ * @param desiredRetention - Target retention rate (default 0.9)
   212→ * @returns Hours until next review
   213→ */
   214→function calculateNextInterval(
   215→  stability: number,
   216→  desiredRetention: number = FSRS_DESIRED_RETENTION
   217→): number {
   218→  const w = FSRS_DECAY_SHARPNESS;
   219→  const days = stability * (Math.pow(1.0 / desiredRetention, w) - 1.0) * 9.0;
   220→
   221→  // Convert to hours and clamp
   222→  let hours = Math.floor(days * 24.0);
   223→  hours = Math.max(1, Math.min(MAX_INTERVAL_HOURS, hours));
   224→
   225→  return hours;
   226→}
   227→
   228→// ============================================================================
   229→// PUBLIC API
   230→// ============================================================================
   231→
   232→/**
   233→ * Create a new flashcard with default FSRS parameters
   234→ *
   235→ * Initial state:
   236→ * - Stability: 1.0 day
   237→ * - Difficulty: 0.3 (moderate)
   238→ * - No reviews or lapses
   239→ * - Next review scheduled immediately
   240→ *
   241→ * @returns A new FSRSCard with initial values
   242→ */
   243→export function createCard(): FSRSCard {
   244→  const now = new Date();
   245→
   246→  return {
   247→    stability: FSRS_INITIAL_STABILITY,
   248→    difficulty: FSRS_INITIAL_DIFFICULTY,
   249→    lastReview: now,
   250→    nextReview: now, // Due immediately for first review
   251→    lapses: 0,
   252→    reps: 0,
   253→  };
   254→}
   255→
   256→/**
   257→ * Update a flashcard after a review session
   258→ *
   259→ * This is the main function that applies the FSRS algorithm:
   260→ * 1. Calculates current retrievability
   261→ * 2. Updates stability and difficulty based on quality
   262→ * 3. Schedules next review
   263→ * 4. Updates review counters
   264→ *
   265→ * @param card - The flashcard being reviewed
   266→ * @param quality - Quality rating (1=again, 2=hard, 3=good, 4=easy)
   267→ * @returns Updated card with new FSRS parameters
   268→ */
   269→export function reviewCard(card: FSRSCard, quality: Quality): FSRSCard {
   270→  const now = new Date();
   271→
   272→  // Calculate current retrievability
   273→  const R = calculateRetrievability(card);
   274→
   275→  // Update counters
   276→  const newReps = card.reps + 1;
   277→  const newLapses = quality === 1 ? card.lapses + 1 : card.lapses;
   278→
   279→  // Calculate new FSRS parameters
   280→  const newStability = calculateNewStability(
   281→    card.stability,
   282→    card.difficulty,
   283→    R,
   284→    quality,
   285→    newLapses
   286→  );
   287→
   288→  const newDifficulty = calculateNewDifficulty(card.difficulty, quality);
   289→
   290→  // Calculate next review time
   291→  const hoursUntilNext = calculateNextInterval(newStability, FSRS_DESIRED_RETENTION);
   292→  const nextReview = new Date(now.getTime() + hoursUntilNext * 60 * 60 * 1000);
   293→
   294→  return {
   295→    stability: newStability,
   296→    difficulty: newDifficulty,
   297→    lastReview: now,
   298→    nextReview,
   299→    lapses: newLapses,
   300→    reps: newReps,
   301→  };
   302→}
   303→
   304→/**
   305→ * Get the next scheduled review date for a card
   306→ *
   307→ * @param card - The flashcard to check
   308→ * @returns The scheduled review date
   309→ */
   310→export function getNextReviewDate(card: FSRSCard): Date {
   311→  return card.nextReview;
   312→}
   313→
   314→/**
   315→ * Check if a card is due for review
   316→ *
   317→ * @param card - The flashcard to check
   318→ * @returns true if the card should be reviewed now
   319→ */
   320→export function isDue(card: FSRSCard): boolean {
   321→  const now = new Date();
   322→  return card.nextReview.getTime() <= now.getTime();
   323→}
   324→
   325→/**
   326→ * Calculate statistics for a collection of cards
   327→ *
   328→ * @param cards - Array of flashcards to analyze
   329→ * @returns Statistics object with performance metrics
   330→ */
   331→export function calculateStats(cards: FSRSCard[]): FSRSStats {
   332→  if (cards.length === 0) {
   333→    return {
   334→      totalCards: 0,
   335→      cardsDue: 0,
   336→      cardsMastered: 0,
   337→      avgStability: 0,
   338→      avgDifficulty: 0,
   339→      predictedRetention: 0,
   340→    };
   341→  }
   342→
   343→  const now = new Date();
   344→  let totalStability = 0;
   345→  let totalDifficulty = 0;
   346→  let totalRetention = 0;
   347→  let cardsDue = 0;
   348→  let cardsMastered = 0;
   349→
   350→  for (const card of cards) {
   351→    totalStability += card.stability;
   352→    totalDifficulty += card.difficulty;
   353→    totalRetention += calculateRetrievability(card);
   354→
   355→    if (card.nextReview.getTime() <= now.getTime()) {
   356→      cardsDue++;
   357→    }
   358→
   359→    if (card.stability > 30) {
   360→      cardsMastered++;
   361→    }
   362→  }
   363→
   364→  return {
   365→    totalCards: cards.length,
   366→    cardsDue,
   367→    cardsMastered,
   368→    avgStability: totalStability / cards.length,
   369→    avgDifficulty: totalDifficulty / cards.length,
   370→    predictedRetention: totalRetention / cards.length,
   371→  };
   372→}
   373→
   374→/**
   375→ * Get cards that are due for review, sorted by priority
   376→ *
   377→ * Cards are sorted by next review date (earliest first)
   378→ *
   379→ * @param cards - Array of all flashcards
   380→ * @param limit - Maximum number of cards to return (optional)
   381→ * @returns Array of cards due for review
   382→ */
   383→export function getDueCards(cards: FSRSCard[], limit?: number): FSRSCard[] {
   384→  const now = new Date();
   385→  const dueCards = cards
   386→    .filter(card => card.nextReview.getTime() <= now.getTime())
   387→    .sort((a, b) => a.nextReview.getTime() - b.nextReview.getTime());
   388→
   389→  return limit ? dueCards.slice(0, limit) : dueCards;
   390→}
   391→
   392→/**
   393→ * Predict retention rate at a future date
   394→ *
   395→ * @param card - The flashcard to predict for
   396→ * @param futureDate - Date to predict retention at
   397→ * @returns Predicted probability of recall (0.0 to 1.0)
   398→ */
   399→export function predictRetention(card: FSRSCard, futureDate: Date): number {
   400→  const daysElapsed = (futureDate.getTime() - card.lastReview.getTime()) / (1000 * 60 * 60 * 24);
   401→
   402→  if (card.stability <= 0 || daysElapsed < 0) {
   403→    return 1.0;
   404→  }
   405→
   406→  const r = Math.pow(1.0 + daysElapsed / (9.0 * card.stability), -1.0 / FSRS_DECAY_SHARPNESS);
   407→  return Math.max(0.0, Math.min(1.0, r));
   408→}
   409→
   410→/**
   411→ * Export constants for external use
   412→ */
   413→export const FSRS_CONSTANTS = {
   414→  INITIAL_STABILITY: FSRS_INITIAL_STABILITY,
   415→  INITIAL_DIFFICULTY: FSRS_INITIAL_DIFFICULTY,
   416→  DESIRED_RETENTION: FSRS_DESIRED_RETENTION,
   417→  MIN_STABILITY_DAYS,
   418→  MAX_STABILITY_DAYS,
   419→} as const;
