     1→// ============================================================================
     2→// SSE ENDPOINT FOR TOOL EVENTS
     3→// Real-time updates when Maestri build tools (mindmaps, quizzes, flashcards)
     4→// Part of Phase 1-6: Conversation-First Architecture
     5→// ============================================================================
     6→
     7→import { NextRequest } from 'next/server';
     8→import { nanoid } from 'nanoid';
     9→import {
    10→  registerClient,
    11→  unregisterClient,
    12→  sendHeartbeat,
    13→  HEARTBEAT_INTERVAL_MS,
    14→} from '@/lib/realtime/tool-events';
    15→import { logger } from '@/lib/logger';
    16→import { validateAuth, validateSessionOwnership } from '@/lib/auth/session-auth';
    17→
    18→export const runtime = 'nodejs';
    19→export const dynamic = 'force-dynamic';
    20→
    21→/**
    22→ * GET /api/tools/sse
    23→ * Server-Sent Events endpoint for tool creation updates
    24→ *
    25→ * Query params:
    26→ * - sessionId: Required. The conversation session ID
    27→ *
    28→ * Events:
    29→ * - tool:created - New tool started building
    30→ * - tool:update - Incremental content update
    31→ * - tool:complete - Tool finished
    32→ * - tool:error - Error occurred
    33→ * - mindmap:modify - Mindmap modification (voice commands)
    34→ */
    35→export async function GET(request: NextRequest) {
    36→  // #86: Authentication check - SSE requires authenticated user
    37→  const auth = await validateAuth();
    38→  if (!auth.authenticated || !auth.userId) {
    39→    return new Response(
    40→      JSON.stringify({ error: 'Authentication required' }),
    41→      { status: 401, headers: { 'Content-Type': 'application/json' } }
    42→    );
    43→  }
    44→
    45→  const { searchParams } = new URL(request.url);
    46→  const sessionId = searchParams.get('sessionId');
    47→
    48→  // Validate session ID
    49→  if (!sessionId) {
    50→    return new Response(
    51→      JSON.stringify({ error: 'sessionId is required' }),
    52→      { status: 400, headers: { 'Content-Type': 'application/json' } }
    53→    );
    54→  }
    55→
    56→  // Validate sessionId format (prevent path traversal)
    57→  if (!/^[a-zA-Z0-9_-]+$/.test(sessionId)) {
    58→    return new Response(
    59→      JSON.stringify({ error: 'Invalid sessionId format' }),
    60→      { status: 400, headers: { 'Content-Type': 'application/json' } }
    61→    );
    62→  }
    63→
    64→  // #86: Verify session ownership - user can only subscribe to their own sessions
    65→  const ownsSession = await validateSessionOwnership(sessionId, auth.userId);
    66→  if (!ownsSession) {
    67→    return new Response(
    68→      JSON.stringify({ error: 'Session not found or access denied' }),
    69→      { status: 403, headers: { 'Content-Type': 'application/json' } }
    70→    );
    71→  }
    72→
    73→  const clientId = nanoid();
    74→
    75→  logger.info('SSE connection requested', { sessionId, clientId });
    76→
    77→  // Create readable stream for SSE
    78→  const stream = new ReadableStream<Uint8Array>({
    79→    start(controller) {
    80→      // Register this client
    81→      registerClient(clientId, sessionId, controller);
    82→
    83→      // Send initial connection event
    84→      const connectEvent = `data: ${JSON.stringify({
    85→        type: 'connected',
    86→        clientId,
    87→        sessionId,
    88→        timestamp: Date.now(),
    89→      })}\n\n`;
    90→      controller.enqueue(new TextEncoder().encode(connectEvent));
    91→
    92→      // Set up heartbeat interval
    93→      const heartbeatInterval = setInterval(() => {
    94→        const success = sendHeartbeat(clientId);
    95→        if (!success) {
    96→          clearInterval(heartbeatInterval);
    97→        }
    98→      }, HEARTBEAT_INTERVAL_MS);
    99→
   100→      // Clean up on abort
   101→      request.signal.addEventListener('abort', () => {
   102→        clearInterval(heartbeatInterval);
   103→        unregisterClient(clientId);
   104→        try {
   105→          controller.close();
   106→        } catch {
   107→          // Already closed
   108→        }
   109→        logger.info('SSE connection aborted', { sessionId, clientId });
   110→      });
   111→    },
   112→
   113→    cancel() {
   114→      unregisterClient(clientId);
   115→      logger.info('SSE connection cancelled', { sessionId, clientId });
   116→    },
   117→  });
   118→
   119→  return new Response(stream, {
   120→    headers: {
   121→      'Content-Type': 'text/event-stream',
   122→      'Cache-Control': 'no-cache, no-transform',
   123→      'Connection': 'keep-alive',
   124→      'X-Accel-Buffering': 'no', // Disable nginx buffering
   125→    },
   126→  });
   127→}
   128→

